package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.model.AfwezigheidBO;
import be.schaubroeck.lpb.tools.model.OvereenkomstRkmAlgemeenDataBO;
import lombok.AllArgsConstructor;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.JAARBEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.util.CodeExtensie.DEELTIJDSE_WERKHERVATTING;

@AllArgsConstructor
public class PrestatiesDeeltijdseWerkhervatting {

    private static final BigDecimal PERCENTAGE = new BigDecimal("0.375");

    private final LoonElementVerwerker loonElementVerwerker;

    private final PrestatiesDisponibiliteit prestatiesDisponibiliteit;
    private final Disponibiliteit disponibiliteit;

    public void verwerk(
            LoonElementManager manager, LoonCodeManager loonCodeManager, RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, PrestatieSamenvatting samenvatting,
            BigDecimal prestatieNoemer, Opper opper, MoneyMap<AardKodeExtensie> carryoverMap) {
        GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        if (heeftDeeltijdseWerkHervatting(opper) && samenvatting.getTotaalTeller().signum() > 0 && opper.getOvereenkomst() != null) {
            Money basisBedrag = bepaalBasisBedrag(manager, rekenTijd, looncodeGewoonLoon, opper);
            Money bedrag = berekenBedragVoorTeller(basisBedrag, samenvatting.getTotaalTeller(), prestatieNoemer).round(2);
            AardKodeExtensie looncode = gewoonLoon.createDeeltijdseWerkhervatting(opper.getOvereenkomst().getPeriode());
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncode, bedrag, rekenTijd, carryoverMap);
        }
    }

    private Money bepaalBasisBedrag(LoonElementManager manager, RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, Opper opper) {
        OvereenkomstRkmAlgemeenDataBO overeenkomst = opper.getOvereenkomst();
        BasisDispo basisDispoJaar = prestatiesDisponibiliteit.bepaalBasisDispo(manager, rekenTijd, looncodeGewoonLoon, opper, RekenBrutoKey.JAARBEDRAG_KEY);
        BasisDispo basisDispo = basisDispoJaar.divide(12);
        BigDecimal percentageDispo60 = disponibiliteit.bepaalPercentage60(opper, rekenTijd);
        Money bedragBasisDispo = basisDispo.getBedragDispo().multiply(percentageDispo60).add(basisDispo.getBedragDispo100());
        BigDecimal contractUren = opper.getAfwezighedenInvoerModule()
                .stream()
                .filter(abo -> !LoonCodeTools.matches(abo.getAardKodeExtensie(), DEELTIJDSE_WERKHERVATTING))
                .map(AfwezigheidBO::getHours)
                .reduce(overeenkomst.getContractUren(), BigDecimal::subtract);
        Money wachtgeld60 = berekenBedragVoorTeller(bedragBasisDispo, contractUren, overeenkomst.getMaatman()).round(2);
        Money basisBruto = bepaalBasisBruto(manager, opper);
        Money brutoTeBetalenUren = berekenBedragVoorTeller(basisBruto, overeenkomst.getTeBetalenUren(), overeenkomst.getMaatman()).round(2);
        BigDecimal uren = bepaalAfwezigheidsUrenDeeltijdseWerkhervatting(opper);
        Money basisGewoonLoon = bepaalBasisGewoonLoon(manager, looncodeGewoonLoon, opper);
        Money vergoedingDeeltijdseWerkhervatting = berekenBedragVoorTeller(basisGewoonLoon, uren, overeenkomst.getMaatman()).multiply(PERCENTAGE).round(2);

        Money totaal = brutoTeBetalenUren.add(vergoedingDeeltijdseWerkhervatting);

        if (totaal.compareTo(wachtgeld60) >= 0 || overeenkomst.getTeBetalenUren().signum() == 0) {
            return vergoedingDeeltijdseWerkhervatting;
        } else {
            return wachtgeld60.subtract(brutoTeBetalenUren);
        }
    }

    private boolean heeftDeeltijdseWerkHervatting(Opper opper) {
        return opper.getAfwezighedenInvoerModule() != null && opper.getAfwezighedenInvoerModule().stream()
                .anyMatch(x -> LoonCodeTools.matches(x.getAardKodeExtensie(), DEELTIJDSE_WERKHERVATTING));
    }

    private BigDecimal bepaalAfwezigheidsUrenDeeltijdseWerkhervatting(Opper opper) {
        return opper.getAfwezighedenInvoerModule().stream()
                .filter(x -> LoonCodeTools.matches(x.getAardKodeExtensie(), DEELTIJDSE_WERKHERVATTING))
                .map(AfwezigheidBO::getHours)
                .findAny().orElse(BigDecimal.ZERO);
    }

    private Money bepaalBasisGewoonLoon(LoonElementManager manager, AardKodeExtensie looncodeGewoonLoon, Opper opper) {
        return manager.getOpperElementen(opper).stream()
                .filter(x -> x.getAardKodeExtensie().equals(looncodeGewoonLoon))
                .map(x -> x.getPropertyMoney(JAARBEDRAG_KEY).divide(12))
                .findAny().orElse(Money.ZERO).round(2);
    }


    private Money bepaalBasisBruto(LoonElementManager manager, Opper opper) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        Money bedrag = Money.ZERO;
        for (LoonElement element : loonElementen) {
            Money basisBedrag = element.getPropertyMoney(JAARBEDRAG_KEY).divide(12).round(2);
            bedrag = bedrag.add(basisBedrag);
        }
        return bedrag;
    }

    private Money berekenBedragVoorTeller(Money bedrag, BigDecimal teller, BigDecimal noemer) {
        return bedrag.multiply(teller).divide(noemer);
    }
}
